-- DELETE (filterable, transactional)
DELETE FROM orders WHERE status = 'CANCELLED';

-- TRUNCATE (all rows, fast)
TRUNCATE TABLE temp_data;

-- DROP (removes table entirely)
DROP TABLE IF EXISTS old_table;

-- Function
CREATE FUNCTION get_discount(price DECIMAL) RETURNS DECIMAL
DETERMINISTIC
RETURN price * 0.9;

-- Stored procedure
CREATE PROCEDURE update_stock(IN product_id INT, IN qty INT)
BEGIN
  UPDATE products SET stock = stock - qty WHERE id = product_id;
END;

-- View
CREATE VIEW active_users AS
  SELECT id, name, email FROM users WHERE active = 1;

-- Session A (REPEATABLE READ)
START TRANSACTION;
SELECT balance FROM accounts WHERE id = 1; -- sees 1000

-- Session B commits: UPDATE accounts SET balance=900 WHERE id=1;

-- Session A still sees 1000 (snapshot from start of txn)
SELECT balance FROM accounts WHERE id = 1; -- still 1000
COMMIT;

-- Phantom read scenario
-- T1:
START TRANSACTION;
SELECT * FROM employees WHERE dept_id = 5 FOR UPDATE;
-- InnoDB places next-key lock: prevents any INSERT into dept_id=5 gap

-- T2 (concurrent):
INSERT INTO employees (name, dept_id) VALUES ('Alice', 5);
-- BLOCKED until T1 commits

-- Query: SELECT user_id, status FROM orders WHERE created_at > '2024-01-01'

-- Without covering index:
CREATE INDEX idx_created ON orders (created_at);
-- → finds rows via index, then fetches user_id+status from table (row lookup)

-- With covering index:
CREATE INDEX idx_created_covering ON orders (created_at, user_id, status);
-- → all columns served from index, no table access
-- EXPLAIN Extra: 'Using index'

EXPLAIN SELECT user_id, status FROM orders WHERE created_at > '2024-01-01';

-- Sharding concept (application-level routing)
int shardId = userId % NUM_SHARDS; // e.g., userId=123, shards=4 → shard 3
DataSource ds = shardPool.get(shardId);

-- Partition (database-level, single server)
PARTITION BY HASH(user_id) PARTITIONS 8;
-- MySQL automatically routes rows to the right partition

-- These return 0 rows even if NULL exists:
SELECT * FROM users WHERE age = NULL;    -- WRONG
SELECT * FROM users WHERE age != NULL;   -- WRONG

-- Correct:
SELECT * FROM users WHERE age IS NULL;
SELECT * FROM users WHERE age IS NOT NULL;

-- NULL in aggregation
SELECT COUNT(*), COUNT(age), AVG(age) FROM users;
-- COUNT(*) = 5, COUNT(age) = 3 (if 2 are NULL), AVG = avg of 3 non-null values

-- COALESCE
SELECT name, COALESCE(phone, 'N/A') AS contact FROM users;
